import re
from collections import Counter  # словарь-счётчик для подсчёта частот элементов

raw_text = "among other public buildings in a certain town, which for many reasons it will be prudent to refrain from mentioning, and to which i will assign no fictitious name, there is one anciently common to most towns, great or small: to wit, a workhouse and in this workhouse was born on a day and date which i need not trouble myself to repeat, inasmuch as it can be of no possible consequence to the reader, in this stage of the business at all events the item of mortality whose name is prefixed to the head of this chapter. for a long time after it was ushered into this world of sorrow and trouble, by the parish surgeon, it remained a matter of considerable doubt whether the child would survive to bear any name at all in which case it is somewhat more than probable that these memoirs would never have appeared or, if they had, that being comprised within a couple of pages, they would have possessed the inestimable merit of being the most concise and faithful specimen of biography, extant in the literature of any age or country. although i am not disposed to maintain that the being born in a workhouse, is in itself the most fortunate and enviable circumstance that can possibly befall a human being, i do mean to say that in this particular instance, it was the best thing for oliver twist that could by possibility have occurred. the fact is, that there was considerable difficulty in inducing oliver to take upon himself the office of respiration,a troublesome practice, but one which custom has rendered necessary to our easy existence and for some time he lay gasping on a little flock mattress, rather unequally poised between this world and the next: the balance being decidedly in favour of the latter. now, if, during this brief period, oliver had been surrounded by careful grandmothers, anxious aunts, experienced nurses, and doctors of profound wisdom, he would most inevitably and indubitably have been killed in no time. there being nobody by, however, but a pauper old woman, who was rendered rather misty by an unwonted allowance of beer and a parish surgeon who did such matters by contract oliver and nature fought out the point between them. the result was, that, after a few struggles, oliver breathed, sneezed, and proceeded to advertise to the inmates of the workhouse the fact of a new burden having been imposed upon the parish, by setting up as loud a cry as could reasonably have been expected from a male infant who had not been possessed of that very useful appendage, a voice, for a much longer space of time than three minutes and a quarter. as oliver gave this first proof of the free and proper action of his lungs, the patchwork coverlet which was carelessly flung over the iron bedstead, rustled the pale face of a young woman was raised feebly from the pillow and a faint voice imperfectly articulated the words, 'let me see the child, and die.' the surgeon had been sitting with his face turned towards the fire: giving the palms of his hands a warm and a rub alternately. as the young woman spoke, he rose, and advancing to the bed's head, said, with more kindness than might have been expected of him: 'oh, you must not talk about dying yet.' 'lor bless her dear heart, no' interposed the nurse, hastily depositing in her pocket a green glass bottle, the contents of which she had been tasting in a corner with evident satisfaction. 'lor bless her dear heart, when she has lived as long as i have, sir, and had thirteen children of her own, and all on 'em dead except two, and them in the wurkus with me, she'll know better than to take on in that way, bless her dear heart think what it is to be a mother, there's a dear young lamb do.' apparently this consolatory perspective of a mother's prospects failed in producing its due effect. the patient shook her head, and stretched out her hand towards the child. the surgeon deposited it in her arms. she imprinted her cold white lips passionately on its forehead passed her hands over her face gazed wildly round shuddered fell backand died. they chafed her breast, hands, and temples but the blood had stopped forever. they talked of hope and comfort. they had been strangers too long. 'it's all over, mrs. thingummy' said the surgeon at last. 'ah, poor dear, so it is' said the nurse, picking up the cork of the green bottle, which had fallen out on the pillow, as she stooped to take up the child. 'poor dear' 'you needn't mind sending up to me, if the child cries, nurse,' said the surgeon, putting on his gloves with great deliberation. 'it's very likely it will be troublesome. give it a little gruel if it is.' he put on his hat, and, pausing by the bed-side on his way to the door, added, 'she was a good-looking girl, too where did she come from' 'she was brought here last night,' replied the old woman, 'by the overseer's order. she was found lying in the street. she had walked some distance, for her shoes were worn to pieces but where she came from, or where she was going to, nobody knows.' the surgeon leaned over the body, and raised the left hand. 'the old story,' he said, shaking his head: 'no wedding-ring, i see. ah good-night' the medical gentleman walked away to dinner and the nurse, having once more applied herself to the green bottle, sat down on a low chair before the fire, and proceeded to dress the infant. what an excellent example of the power of dress, young oliver twist was wrapped in the blanket which had hitherto formed his only covering, he might have been the child of a nobleman or a beggar it would have been hard for the haughtiest stranger to have assigned him his proper station in society. but now that he was enveloped in the old calico robes which had grown yellow in the same service, he was badged and ticketed, and fell into his place at oncea parish childthe orphan of a workhousethe humble, half-starved drudgeto be cuffed and buffeted through the worlddespised by all, and pitied by none. oliver cried lustily. if he could have known that he was an orphan, left to the tender mercies of church-wardens and overseers, perhaps he would have cried the louder. for the next eight or ten months, oliver was the victim of a systematic course of treachery and deception. he was brought up by hand. the hungry and destitute situation of the infant orphan was duly reported by the workhouse authorities to the parish authorities. the parish authorities inquired with dignity of the workhouse authorities, whether there was no female then domiciled in 'the house' who was in a situation to impart to oliver twist, the consolation and nourishment of which he stood in need. the workhouse authorities replied with humility, that there was not. upon this, the parish authorities magnanimously and humanely resolved, that oliver should be 'farmed,' or, in other words, that he should be dispatched to a branch workhouse some three miles off, where twenty or thirty other juvenile offenders against the poor-laws, rolled about the floor all day, without the inconvenience of too much food or too much clothing, under the parental superintendence of an elderly female, who received the culprits at and for the consideration of sevenpence halfpenny per small head per week. sevenpence-halfpenny's worth per week is a good round diet for a child a great deal may be got for sevenpence-halfpenny, quite enough to overload its stomach, and make it uncomfortable. the elderly female was a woman of wisdom and experience she knew what was good for children and she had a very accurate perception of what was good for herself. so, she appropriated the greater part of the weekly stipend to her own use, and consigned the rising parochial generation to even a shorter allowance than was originally provided for them. thereby finding in the lowest depth a deeper still and proving herself a very great experimental philosopher. everybody knows the story of another experimental philosopher who had a great theory about a horse being able to live without eating, and who demonstrated it so well, that he had got his own horse down to a straw a day, and would unquestionably have rendered him a very spirited and rampacious animal on nothing at all, if he had not died, four-and-twenty hours before he was to have had his first comfortable bait of air."


def normalize(s: str) -> str:
    s = s.lower()
    s = re.sub(r"[^a-z]+", " ", s)  # всё что не латинская буква a..z заменяем на пробел
    s = re.sub(r"\s+", " ", s).strip()  # два и более пробела собираем в один
    return s


text = normalize(raw_text)

N = len(text)
alphabet = sorted(set(text))  # отсортированное множество уникальных символов в тексте

char_counts = Counter(text)
char_freq = {ch: char_counts[ch] / N for ch in sorted(char_counts)}  # вероятность встречи символа

bigrams = [text[i:i + 2] for i in range(len(text) - 1)]  # список всех пар соседних символов
M = len(bigrams)  # число биграмм N-1
bigram_counts = Counter(bigrams)  # подсчет сколько раз встречается каждая пара
bigram_freq = {bg: bigram_counts[bg] / M for bg in bigram_counts}  #

print("=== NORMALIZED TEXT INFO ===")
print(f"Length symbols: {N}")
print(f"Alphabet size : {len(alphabet)}")
print(f"Alphabet: {alphabet}")
print()

print("=== SYMBOL STATISTICS ===")
print("symbol - count - probability")
for ch in sorted(char_counts, key=lambda c: (-char_counts[c], c)):
    # char_counts[c] сколько раз встретился символ, мину нужен чтобы сортировка была в обратную сторону (по убыванию)
    # , c нужно если частота некоторых символов одинакова(будет сортировка по коду символа) 
    print(f"{repr(ch)},     {char_counts[ch]},     {char_counts[ch] / N:.8f}")
    # repr для того чтобы пробел был виден в таблице
print()

print("=== BIGRAM STATISTICS (top 50) ===")
print("bigram - count - probability")
for bg, cnt in bigram_counts.most_common(50):
    print(f"{repr(bg)},    {cnt},    {cnt / M:.8f}")
